class Solution:
    def mergeNodes(self, head):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        groups = []
        current = None
        for v in vals[1:]:
            if v == 0:
                groups.append(current or 0)
                current = None
            else:
                current = (current or 0) + v
        dummy = ListNode(0)
        tail = dummy
        for g in groups:
            tail.next = ListNode(g)
            tail = tail.next
        return dummy.next

