class Solution:
    def mergeNodes(self, head):
        dummy = ListNode(0)
        tail = dummy
        cur = head.next
        total = 0
        while cur:
            if cur.val == 0:
                tail.next = ListNode(total)
                tail = tail.next
                total = 0
            else:
                total += cur.val
            cur = cur.next
        return dummy.next

