var mergeNodes = function(head) {
    const dummy = new ListNode(0);
    let tail = dummy;
    let cur = head.next;
    let total = 0;
    while (cur) {
        if (cur.val === 0) {
            tail.next = new ListNode(total);
            tail = tail.next;
            total = 0;
        } else {
            total += cur.val;
        }
        cur = cur.next;
    }
    return dummy.next;
};
